import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse(`{"title":"11. Termination Of Employment","description":"","frontmatter":{"title":"11. Termination Of Employment","eba":"Children's Services Award 2010","topics":["wages","employment","termination","consultation","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/employment/11-termination-of-employment.md","filePath":"ebas/childrens-services/employment/11-termination-of-employment.md"}`),r={name:"ebas/childrens-services/employment/11-termination-of-employment.md"};function i(s,e,p,l,m,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_11-termination-of-employment" tabindex="-1">11. Termination Of Employment <a class="header-anchor" href="#_11-termination-of-employment" aria-label="Permalink to &quot;11. Termination Of Employment&quot;">​</a></h1><p>Note: The <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a> sets out requirements for notice of termination by an employer. See ss.117 and 123 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><ol><li><p>Notice of termination by an employee</p><p>a. This clause applies to all employees except those identified in ss.123(1) and 123(3) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>b. An employee must give the employer notice of termination in accordance with <strong>Table 1---Period of notice</strong> of at least the period specified in column 2 according to the period of continuous service of the employee specified in column 1.</p></li></ol><p><strong>Table 1---Period of notice</strong></p><hr><p><strong>Column 1\\</strong> Column 2\\ Employee&#39;s period of continuous service with the employer at the end of the day the notice is given <strong>Period of notice</strong></p><hr><p>Not more than 1 year 1 week</p><p>More than 1 year but not more than 3 years 2 weeks</p><p>More than 3 years but not more than 5 years 3 weeks</p><p>More than 5 years 4 weeks</p><hr><p>Note: The notice of termination required to be given by an employee is the same as that required of an employer except that the employee does not have to give additional notice based on the age of the employee.</p><p>c. In paragraph (b) <strong>continuous service</strong> has the same meaning as in s.117 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>d. If an employee who is at least 18 years old does not give the period of notice required under paragraph (b), then the employer may deduct from wages due to the employee under this award an amount that is no more than one week&#39;s wages for the employee.</p><p>e. If the employer has agreed to a shorter period of notice than that required under paragraph (b), then no deduction can be made under paragraph (d).</p><p>f. Any deduction made under paragraph (d) must not be unreasonable in the circumstances.</p><ol><li>Job search entitlement</li></ol><p>Where an employer has given notice of termination to an employee, the employee must be allowed time off without loss of pay of up to one day for the purpose of seeking other employment.</p><ol><li>The time off under clause 11.2 is to be taken at times that are convenient to the employee after consultation with the employer.</li></ol><p>Plain language terms: resignation, notice, dismissal.</p>',21)])])}const f=t(r,[["render",i]]);export{d as __pageData,f as default};
